{
  "items": [
    {
      "panel_index": 1,
      "ai_view": "Lý Vân Tâm đứng lặng nhìn một chiếc thuyền gỗ trôi trên mặt nước. Gió thổi nhẹ, tiếng nước chảy róc rách.",
      "voiceover_text": "Một nơi xa lạ. Một khởi đầu bí ẩn."
    },
    {
      "panel_index": 2,
      "ai_view": "Người này nhìn xuống một khu vực tối, ánh mắt đầy tò mò nhưng cũng có chút lo lắng. Một bóng đen thoáng qua phía trước.",
      "voiceover_text": "Tò mò... nhưng điều gì đang ẩn nấp?"
    },
